/**
 * Homepage: loads `apis/catalog.json` (generated by scripts/build-api-portal.py),
 * renders module cards and wires up client-side filtering.
 *
 * If catalog fetch fails (e.g. opened as file://), cards already in markup still work.
 */

(function () {
  "use strict";

  function inferInitials(title) {
    var parts = title.split(/\s+/).filter(Boolean);
    if (!parts.length) return "?";
    if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
    return (parts[0][0] + parts[1][0]).toUpperCase();
  }

  function buildCard(api) {
    var a = document.createElement("a");
    a.className = "api-card";
    a.href = "./docs/" + encodeURIComponent(api.id) + ".html";
    a.setAttribute("data-search", (
      api.title + " " + (api.specTitle || "") + " " + api.description + " " + api.file
    ).toLowerCase());

    var initials = inferInitials(api.title);

    a.innerHTML =
      '<span class="api-card__icon" aria-hidden="true">' +
      initials +
      "</span>" +
      '<h2 class="api-card__title">' +
      escapeHtml(api.title) +
      "</h2>" +
      (api.specTitle
        ? '<p class="api-card__spec-title">' + escapeHtml(api.specTitle) + "</p>"
        : "") +
      '<p class="api-card__desc">' +
      escapeHtml(api.description || "") +
      "</p>" +
      '<span class="api-card__cta">Open API reference →</span>';

    a.title = api.title + " — Open Swagger UI";

    return a;
  }

  function escapeHtml(s) {
    return String(s || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/"/g, "&quot;")
      .replace(/>/g, "&gt;");
  }

  function applyFilter(grid, query) {
    var q = query.trim().toLowerCase();
    var cards = grid.querySelectorAll(".api-card");
    var visible = 0;
    cards.forEach(function (card) {
      var haystack = card.getAttribute("data-search") || "";
      var show = !q || haystack.indexOf(q) !== -1;
      card.hidden = !show;
      if (show) visible++;
    });

    var meta = document.querySelector("[data-role='filter-meta']");
    if (meta) {
      meta.textContent = visible + " module" + (visible === 1 ? "" : "s");
    }

    /** Support deep-ish linking: opening /index.html?q=channels auto-fills filter */
    if (typeof history !== "undefined" && typeof history.replaceState === "function") {
      try {
        var url = new URL(window.location.href);
        if (q) url.searchParams.set("q", query.trim());
        else url.searchParams.delete("q");
        history.replaceState(null, "", url.pathname + url.search + url.hash);
      } catch (_) {
        /* noop */
      }
    }
  }

  async function populate() {
    var grid = document.getElementById("api-cards");
    if (!grid) return;

    var catalogUrl = new URL("apis/catalog.json", window.location.href).href;
    var res = await fetch(catalogUrl, { credentials: "same-origin" });
    if (!res.ok) return;

    var data = await res.json();
    var apis = data.apis || [];
    grid.innerHTML = "";
    apis.forEach(function (api) {
      grid.appendChild(buildCard(api));
    });

    var input = document.getElementById("api-filter");
    if (!input) return;

    var params = new URLSearchParams(window.location.search);
    if (params.get("q")) {
      input.value = params.get("q");
    }

    applyFilter(grid, input.value);

    input.addEventListener("input", function () {
      applyFilter(grid, input.value);
    });
    input.form && input.form.addEventListener("submit", function (e) {
      e.preventDefault();
    });
  }

  populate().catch(function (err) {
    console.warn("[api-portal] Could not hydrate catalog:", err);

    /** Still wire filter against any static/markup-rendered cards. */
    var grid = document.getElementById("api-cards");
    var input = document.getElementById("api-filter");
    if (!grid || !input) return;
    grid.querySelectorAll(".api-card").forEach(function (card) {
      if (!card.getAttribute("data-search")) {
        card.setAttribute("data-search", card.textContent.trim().toLowerCase());
      }
    });
    input.addEventListener("input", function () {
      applyFilter(grid, input.value);
    });

    /** Handle ?q even without catalog hydration */
    var params = new URLSearchParams(window.location.search);
    if (params.get("q")) input.value = params.get("q");
    applyFilter(grid, input.value);
  });
})();
